function createRawAttachment(
	overrides: Partial<RawAttachment> & {
		messageUid: MessageUid;
	},
): RawAttachment {
	return {
		contentType: "application/octet-stream",
		filename: undefined,
		size: 0,
		data: new Uint8Array(0),
		...overrides,
	};
}

/** application/pdf, ~200 bytes, eligible. */
export function eligiblePdfAttachment(uid: number): RawAttachment {
	return createRawAttachment({
		messageUid: uid as MessageUid,
		contentType: "application/pdf",
		filename: "doc.pdf",
		size: MINIMAL_PDF.length,
		data: new Uint8Array(MINIMAL_PDF),
	});
}

/** image/jpeg, 100_001 bytes (≥ MIN_EMAIL_IMAGE_SIZE), eligible. */
export function eligibleImageAttachment(uid: number): RawAttachment {
	const data = new Uint8Array(100_001);
	return createRawAttachment({
		messageUid: uid as MessageUid,
		contentType: "image/jpeg",
		filename: "photo.jpg",
		size: data.length,
		data,
	});
}

/** image/jpeg, 50 bytes, ineligible (too small). */
export function ineligibleSmallImage(uid: number): RawAttachment {
	const data = new Uint8Array(50);
	return createRawAttachment({
		messageUid: uid as MessageUid,
		contentType: "image/jpeg",
		filename: "thumb.jpg",
		size: data.length,
		data,
	});
}

/** text/calendar, 100 bytes, blocked MIME type. */
export function blockedIcsAttachment(uid: number): RawAttachment {
	const data = new Uint8Array(100);
	return createRawAttachment({
		messageUid: uid as MessageUid,
		contentType: "text/calendar",
		filename: "event.ics",
		size: data.length,
		data,
	});
}

/** Minimal valid JPEG (~119 bytes). */
const MINIMAL_JPEG = Result.getOrThrow(
	Encoding.decodeBase64(
		"/9j/4AAQSkZJRgABAQEASABIAAD/2wBDAAMCAgMCAgMDAwMEAwMEBQgFBQQEBQoHBwYIDAoMDAsKCwsNDhIQDQ4RDgsLEBYQERMUFRUVDA8XGBYUGBIUFRT/wAALCAABAAEBAREA/8QAFAABAAAAAAAAAAAAAAAAAAAACf/EABQQAQAAAAAAAAAAAAAAAAAAAAD/2gAIAQEAAD8AKp//2Q==",
	),
);

/** Minimal text/calendar content (~50 bytes). */
const MINIMAL_ICS = new TextEncoder().encode("BEGIN:VCALENDAR\r\nVERSION:2.0\r\nEND:VCALENDAR\r\n");

/** Signal mock: PDF attachment. Returns Record for merge into fetchAttachmentData. */
export function signalPdfAttachment(id: string): Record<string, Uint8Array> {
	return { [id]: new Uint8Array(MINIMAL_PDF) };
}

/** Signal mock: JPEG attachment (≥100 bytes for file-type detection). */
export function signalImageAttachment(id: string): Record<string, Uint8Array> {
	return { [id]: new Uint8Array(MINIMAL_JPEG) };
}

/** Signal mock: ineligible attachment (text/calendar). */
export function signalIneligibleAttachment(id: string): Record<string, Uint8Array> {
	return { [id]: new Uint8Array(MINIMAL_ICS) };
}
